// Get city name from the current input item
const city = $input.item.json.city;

// Your OpenWeatherMap API key
const apiKey = "1a2e1e08710cff847a8b7ec37dff8035";

// Function to retry API requests if they fail
const fetchWithRetry = async (options, maxRetries = 3) => {

  // Initial wait time before retrying
  let delay = 1000;

  // Loop for retry attempts
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {

      // Make the API request
      return await this.helpers.httpRequest(options);

    } catch (err) {

      // If this is the last attempt, throw the error
      if (attempt === maxRetries) throw err;

      // Wait before trying again
      await new Promise(resolve => setTimeout(resolve, delay));

      // Double the delay time (1s → 2s → 4s)
      delay *= 2;
    }
  }
};

// Call OpenWeatherMap Geocoding API to get latitude and longitude
const geoResults = await fetchWithRetry({
  method: 'GET', // HTTP GET request
  url: 'http://api.openweathermap.org/geo/1.0/direct', // Geocoding endpoint
  qs: {
    q: city,      // City name to search
    limit: 1,     // Return only one result
    appid: apiKey // API key
  },
  json: true // Parse response as JSON
});

// Check if no city was found
if (!geoResults || geoResults.length === 0) {

  // Stop workflow and show error
  throw new Error(`City not found: ${city}`);
}

// Extract latitude and longitude from first result
const { lat, lon } = geoResults[0];

// Call Weather API using latitude and longitude
const weatherResult = await fetchWithRetry({
  method: 'GET', // HTTP GET request
  url: 'https://api.openweathermap.org/data/2.5/weather', // Weather endpoint
  qs: {
    lat,          // Latitude
    lon,          // Longitude
    appid: apiKey,// API key
    units: 'metric' // Temperature in Celsius
  },
  json: true // Parse response as JSON
});

// Get the first weather condition from weather array
const [firstWeather] = weatherResult.weather;

// Get city name from response
const { name } = weatherResult;

// Get temperature from response
const { temp } = weatherResult.main;

// Return final result to next node
return {
  json: {

    // City name
    city: name,

    // Temperature in Celsius
    temperatureC: temp,

    // Weather description (e.g., clear sky)
    condition: firstWeather.description
  }
};

/* Flow Summary
Read city name from input.
Call Geocoding API to get latitude and longitude.
If city is not found, throw an error.
Call Weather API using latitude and longitude.
Extract city name, temperature, and weather condition.
Return clean JSON output.
If an API request fails, retry up to 3 times with increasing delays (1s → 2s → 4s). */
